package com.careeros.resume.web;import com.careeros.common.web.PageResponse;import com.careeros.resume.application.ResumeTailoringService;import com.careeros.resume.domain.ResumeVersion;import jakarta.validation.Valid;import jakarta.validation.constraints.NotNull;import org.springframework.core.io.*;import org.springframework.data.domain.Pageable;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.nio.file.*;import java.time.Instant;import java.util.*;
@RestController @RequestMapping("/api/resumes") public class ResumeController{private final ResumeTailoringService service;public ResumeController(ResumeTailoringService s){service=s;}@PostMapping("/generate")@ResponseStatus(HttpStatus.CREATED)public Response generate(@Valid@RequestBody GenerateRequest r){return out(service.generate(new ResumeTailoringService.Command(r.jobId,r.applicationId,r.model,r.notes,r.skills,r.softSkills,r.matchExplanation)));}@GetMapping public PageResponse<Response>list(Pageable p){return PageResponse.from(service.list(p),this::out);}@GetMapping("/{id}")public Response get(@PathVariable UUID id){return out(service.get(id));}@GetMapping("/job/{jobId}")public List<Response>job(@PathVariable UUID jobId){return service.history(jobId).stream().map(this::out).toList();}@GetMapping("/{id}/download/{format}")public ResponseEntity<Resource>download(@PathVariable UUID id,@PathVariable String format){Path p=service.artifact(id,format);return ResponseEntity.ok().contentType(format.equalsIgnoreCase("pdf")?MediaType.APPLICATION_PDF:MediaType.parseMediaType("application/vnd.openxmlformats-officedocument.wordprocessingml.document")).header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\""+p.getFileName()+"\"").body(new FileSystemResource(p));}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)public void archive(@PathVariable UUID id){service.archive(id);}@PostMapping("/{id}/restore")public Response restore(@PathVariable UUID id){return out(service.restore(id));}@GetMapping("/health")public ResumeTailoringService.Health health(){return service.health();}private Response out(ResumeVersion v){return new Response(v.getId(),v.getVersionNumber(),v.getStatus().name(),v.getJob()==null?null:v.getJob().getId(),v.getJob()==null?null:v.getJob().getTitle(),v.getApplicationId(),v.getModelUsed(),v.getPromptVersion(),v.getGenerationDurationMs(),v.getValidationResult(),lines(v.getValidationWarnings()),json(v.getGeneratedBullets()),v.isPdfGenerated(),v.isArchived(),v.getCreatedAt());}private List<String>lines(String x){return x==null||x.isBlank()?List.of():Arrays.asList(x.split("\\n"));}@SuppressWarnings("unchecked")private List<String>json(String x){try{return x==null?List.of():new com.fasterxml.jackson.databind.ObjectMapper().readValue(x,List.class);}catch(Exception e){return List.of();}}public record GenerateRequest(@NotNull UUID jobId,UUID applicationId,String model,String notes,List<String>skills,List<String>softSkills,String matchExplanation){}public record Response(UUID id,int versionNumber,String status,UUID jobId,String jobTitle,UUID applicationId,String modelUsed,String promptVersion,Long generationDurationMs,String validationResult,List<String>validationWarnings,List<String>generatedBullets,boolean pdfGenerated,boolean archived,Instant createdAt){} }
